//! Error types for the port-aware primitives.
//!
//! `PortError` is the single error surface for `Vmap`, `BoundedArr`, and
//! `BoundedStr`. Downstream modules re-wrap into their own pipeline errors.

use thiserror::Error;

#[derive(Debug, Error, PartialEq, Eq, Clone, Copy)]
pub enum PortError {
    #[error("capacity overflow")]
    Overflow,
    #[error("invalid utf-8")]
    InvalidUtf8,
}

//! `BoundedStr<N>`: fixed-capacity UTF-8 string, `Copy`, stack-only.
//!
//! Mirrors a SNOBOL4 fixed-width string slot. Constructor validates
//! capacity; `as_str` returns the live prefix.

use super::error::PortError;

#[derive(Clone, Copy, Eq)]
pub struct BoundedStr<const N: usize> {
    buf: [u8; N],
    len: u8,
}

impl<const N: usize> BoundedStr<N> {
    pub const fn new() -> Self {
        Self { buf: [0u8; N], len: 0 }
    }

    pub fn from_str(s: &str) -> Result<Self, PortError> {
        let bytes = s.as_bytes();
        if bytes.len() > N || bytes.len() > u8::MAX as usize {
            return Err(PortError::Overflow);
        }
        let mut buf = [0u8; N];
        let mut i = 0;
        while i < bytes.len() {
            buf[i] = bytes[i];
            i += 1;
        }
        Ok(Self { buf, len: bytes.len() as u8 })
    }

    pub fn as_str(&self) -> &str {
        let n = self.len as usize;
        std::str::from_utf8(&self.buf[..n]).expect("bounded_str: utf8 invariant")
    }

    pub fn len(&self) -> usize {
        self.len as usize
    }

    pub fn is_empty(&self) -> bool {
        self.len == 0
    }
}

impl<const N: usize> Default for BoundedStr<N> {
    fn default() -> Self {
        Self::new()
    }
}

impl<const N: usize> PartialEq for BoundedStr<N> {
    fn eq(&self, other: &Self) -> bool {
        self.as_str() == other.as_str()
    }
}

impl<const N: usize> core::fmt::Debug for BoundedStr<N> {
    fn fmt(&self, f: &mut core::fmt::Formatter<'_>) -> core::fmt::Result {
        write!(f, "BoundedStr({:?})", self.as_str())
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn roundtrip_basic() {
        let s = BoundedStr::<16>::from_str("hello").unwrap();
        assert_eq!(s.as_str(), "hello");
        assert_eq!(s.len(), 5);
        assert!(!s.is_empty());
    }

    #[test]
    fn empty_defaults() {
        let s: BoundedStr<8> = BoundedStr::new();
        assert!(s.is_empty());
        assert_eq!(s.as_str(), "");
        assert_eq!(s.len(), 0);
        assert_eq!(s, BoundedStr::<8>::default());
    }

    #[test]
    fn overflow_returns_err() {
        let r = BoundedStr::<4>::from_str("hello");
        assert_eq!(r, Err(PortError::Overflow));
    }

    #[test]
    fn exact_fit_at_capacity() {
        let s = BoundedStr::<5>::from_str("hello").unwrap();
        assert_eq!(s.as_str(), "hello");
        assert_eq!(s.len(), 5);
    }

    #[test]
    fn equality_by_content() {
        let a = BoundedStr::<16>::from_str("x").unwrap();
        let b = BoundedStr::<16>::from_str("x").unwrap();
        let c = BoundedStr::<16>::from_str("y").unwrap();
        assert_eq!(a, b);
        assert_ne!(a, c);
    }

    #[test]
    fn value_is_copy() {
        let s = BoundedStr::<4>::from_str("ab").unwrap();
        let t = s;
        let u = s;
        assert_eq!(t.as_str(), "ab");
        assert_eq!(u.as_str(), "ab");
    }
}

//! `BoundedArr<T, N>`: stack-allocated fixed-capacity array.
//!
//! Mirrors a SNOBOL4 ARRAY with explicit length discipline. `push`
//! fails with `PortError::Overflow` at capacity — no reallocation.

use super::error::PortError;

#[derive(Clone, Copy)]
pub struct BoundedArr<T: Copy, const N: usize> {
    data: [Option<T>; N],
    len: usize,
}

impl<T: Copy, const N: usize> BoundedArr<T, N> {
    pub const fn new() -> Self {
        Self { data: [None; N], len: 0 }
    }

    pub fn push(&mut self, v: T) -> Result<(), PortError> {
        if self.len >= N {
            return Err(PortError::Overflow);
        }
        self.data[self.len] = Some(v);
        self.len += 1;
        Ok(())
    }

    pub fn get(&self, i: usize) -> Option<&T> {
        if i >= self.len {
            return None;
        }
        self.data[i].as_ref()
    }

    pub fn get_mut(&mut self, i: usize) -> Option<&mut T> {
        if i >= self.len {
            return None;
        }
        self.data[i].as_mut()
    }

    pub fn len(&self) -> usize {
        self.len
    }

    pub fn is_empty(&self) -> bool {
        self.len == 0
    }

    pub fn capacity(&self) -> usize {
        N
    }

    pub fn iter(&self) -> impl Iterator<Item = &T> + '_ {
        self.data[..self.len].iter().filter_map(|x| x.as_ref())
    }
}

impl<T: Copy, const N: usize> Default for BoundedArr<T, N> {
    fn default() -> Self {
        Self::new()
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn push_then_get() {
        let mut a: BoundedArr<i32, 4> = BoundedArr::new();
        a.push(10).unwrap();
        a.push(20).unwrap();
        assert_eq!(a.get(0), Some(&10));
        assert_eq!(a.get(1), Some(&20));
        assert_eq!(a.get(2), None);
        assert_eq!(a.len(), 2);
        assert_eq!(a.capacity(), 4);
    }

    #[test]
    fn overflow_at_capacity() {
        let mut a: BoundedArr<u8, 2> = BoundedArr::new();
        a.push(1).unwrap();
        a.push(2).unwrap();
        assert_eq!(a.push(3), Err(PortError::Overflow));
        assert_eq!(a.len(), 2);
    }

    #[test]
    fn empty_array() {
        let a: BoundedArr<i32, 4> = BoundedArr::new();
        assert!(a.is_empty());
        assert_eq!(a.len(), 0);
        assert_eq!(a.get(0), None);
        assert_eq!(a.iter().count(), 0);
    }

    #[test]
    fn get_mut_updates_in_place() {
        let mut a: BoundedArr<i32, 4> = BoundedArr::new();
        a.push(5).unwrap();
        *a.get_mut(0).unwrap() = 7;
        assert_eq!(a.get(0), Some(&7));
        assert!(a.get_mut(1).is_none());
    }

    #[test]
    fn iter_visits_live_slots_only() {
        let mut a: BoundedArr<i32, 4> = BoundedArr::new();
        a.push(1).unwrap();
        a.push(2).unwrap();
        a.push(3).unwrap();
        let sum: i32 = a.iter().sum();
        assert_eq!(sum, 6);
        assert_eq!(a.iter().count(), 3);
    }
}

//! `Vmap<N>`: linear-scan string-keyed integer map, capacity N.
//!
//! Mirrors SNOBOL4 `VMAP = ' key:val key:val '` — a linear lookup by
//! design. Keys are `BoundedStr<16>`; values are `i32`. No hashing.

use super::bounded_arr::BoundedArr;
use super::bounded_str::BoundedStr;
use super::error::PortError;

pub type VKey = BoundedStr<16>;

#[derive(Clone, Copy)]
pub struct Vmap<const N: usize> {
    ents: BoundedArr<(VKey, i32), N>,
}

impl<const N: usize> Vmap<N> {
    pub const fn new() -> Self {
        Self { ents: BoundedArr::new() }
    }

    pub fn insert(&mut self, k: &str, v: i32) -> Result<(), PortError> {
        let key = VKey::from_str(k)?;
        for i in 0..self.ents.len() {
            let entry = self.ents.get_mut(i).expect("vmap: len invariant");
            if entry.0 == key {
                entry.1 = v;
                return Ok(());
            }
        }
        self.ents.push((key, v))
    }

    pub fn get(&self, k: &str) -> Option<i32> {
        let key = VKey::from_str(k).ok()?;
        for entry in self.ents.iter() {
            if entry.0 == key {
                return Some(entry.1);
            }
        }
        None
    }

    pub fn len(&self) -> usize {
        self.ents.len()
    }

    pub fn is_empty(&self) -> bool {
        self.ents.is_empty()
    }

    pub fn iter(&self) -> impl Iterator<Item = (&VKey, i32)> + '_ {
        self.ents.iter().map(|(k, v)| (k, *v))
    }
}

impl<const N: usize> Default for Vmap<N> {
    fn default() -> Self {
        Self::new()
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn insert_then_get() {
        let mut m: Vmap<8> = Vmap::new();
        m.insert("a", 1).unwrap();
        m.insert("b", 2).unwrap();
        assert_eq!(m.get("a"), Some(1));
        assert_eq!(m.get("b"), Some(2));
        assert_eq!(m.get("c"), None);
        assert_eq!(m.len(), 2);
    }

    #[test]
    fn insert_overwrites_existing_key() {
        let mut m: Vmap<4> = Vmap::new();
        m.insert("x", 1).unwrap();
        m.insert("x", 99).unwrap();
        assert_eq!(m.get("x"), Some(99));
        assert_eq!(m.len(), 1);
    }

    #[test]
    fn overflow_at_capacity() {
        let mut m: Vmap<2> = Vmap::new();
        m.insert("a", 1).unwrap();
        m.insert("b", 2).unwrap();
        assert_eq!(m.insert("c", 3), Err(PortError::Overflow));
    }

    #[test]
    fn key_too_long_overflows() {
        let mut m: Vmap<4> = Vmap::new();
        let long = "0123456789abcdefg";
        assert_eq!(long.len(), 17);
        assert_eq!(m.insert(long, 1), Err(PortError::Overflow));
    }

    #[test]
    fn empty_map() {
        let m: Vmap<4> = Vmap::new();
        assert!(m.is_empty());
        assert_eq!(m.get("anything"), None);
        assert_eq!(m.iter().count(), 0);
    }

    #[test]
    fn iter_visits_all_entries() {
        let mut m: Vmap<4> = Vmap::new();
        m.insert("a", 10).unwrap();
        m.insert("b", 20).unwrap();
        let total: i32 = m.iter().map(|(_, v)| v).sum();
        assert_eq!(total, 30);
    }
}

